//    DESCRIPTION       :
//
//          This logic is used in both generate mode (to create the checkbits)
//          and correct mode (generate checkbits to compare against check_in).
//          If the generated checkword matches the input checkword, there is 
//          no error.
//
//          This ECC logic supports any combination of data and check bits, 
//          up to 1024b data. NOTE: The following rules must be followed:
//
//          for data width 4 or less: 4 check bits
//          for data width 11 or less: 5 check bits
//          for data width 26 or less: 6 check bits
//          for data width 57 or less: 7 check bits
//          for data width 120 or less: 8 check bits
//          for data width 247 or less: 9 check bits
//          for data width 502 or less: 10 check bits
//          for data width 1013 or less: 11 check bits
//          for data width 1024 or less: 12 check bits

//---------------------------------------------------------------------------//
// --------------------------------------------------------------------------//
//      LAST MODIFICATION:      16/02/16
//      RECENT AUTHORS:         yevgeny.yankilevich@intel.com
//      PREVIOUS RELEASES:      
//                              16/02/16: First version.
// --------------------------------------------------------------------------//
module hlp_mgm_ecc_compute #(
        parameter ECC_WDTH_DATA = 500,
        parameter ECC_WDTH_CHK = 5,
        parameter PARITY_ECC_N=1'b0,
        parameter PAR_RES = 8,
        parameter SAMPLE_SYND=1'b0,
        parameter ECC_SAMPLE_EN_PARAM=1'b0
)(/*autoarg*/

   // Outputs
        output logic [ECC_WDTH_DATA-1:0]        data_out                , // in correct_mode, data corrected by ECC. in generate mode data_out = data_in
        output logic [ECC_WDTH_CHK-1:0]         check_out               , // in correct_mode, checkbits corrected by ECC. in generate_mode = generated check bits.
        output logic                            correctable_error       , // in correct_mode, set when a single error is detected and corrected. in generate_mode = 0.
        output logic [ECC_WDTH_CHK-1:0]         syndrome                , // in correct_mode, syndrome of ECC detected error. in generate_mode = 0.
        output logic                            uncorrectable_error     , // in correct_mode, set when uncorrectable bit error detected. in generate_mode = 0

   // Inputs
        input logic                             correct_en              , // enable correct_mode: active high. when cleared, generate_mode is enabled.
        input logic [ECC_WDTH_DATA-1:0]         data_in                 , // input data for both generate_mode and correct_mode.
        input logic [ECC_WDTH_CHK-1:0]          check_in                , // input checkword for correct_mode
        input logic                             clk                     , 
        input logic                             reset_n                 , 
        input logic                             ecc_en                  ,
        input logic                             ecc_invert_1            ,
        input logic                             ecc_invert_2            ,
        input logic                             ecc_sample_en           
   );


// wires and regs

   wire [1023:0] ecc_data_in;
   wire [11:0]   ecc_checkword_in;
   wire [1023:0] corrected_data_1024b;
   reg [11:0]                syndrome_12b;
   wire [11:0]               corrected_checkword_10b;
   wire                     checkword_mismatch;
   reg [11:0]                checkword;
   wire                     correction_match;
   reg [1035:0]              correction_word;
   

logic new_correct_en;
`ifdef  MGM_HLP_FPGA_ALL
        assign new_correct_en = 1'b0;
`else
        assign new_correct_en = correct_en;
`endif

   
   
`ifdef MGM_ECC_REDUCT
// ECC Reduction - In order to remove ECC functionality in FPGA
assign check_out = check_in; 
assign uncorrectable_error = 1'b0;
assign correctable_error = 1'b0;
assign syndrome = 0; 



// ECC Reduction - In order to remove ECC functionality in FPGA
  reg [ECC_WDTH_DATA-1:0] data_outa;
  generate   
    if (ECC_SAMPLE_EN_PARAM) begin
      
      always_ff @(posedge clk or negedge reset_n)        
        if      (~reset_n     ) data_outa <= {ECC_WDTH_DATA{1'b0}} ;  
        else if (ecc_sample_en) data_outa <= data_in               ;

    end else begin
             
      always_ff @(posedge clk or negedge reset_n)
        if (~reset_n) data_outa <= {ECC_WDTH_DATA{1'b0}} ;  
        else          data_outa <= data_in;                 
    
    end
  endgenerate

always_comb
if (SAMPLE_SYND && !PARITY_ECC_N) 
    data_out = data_outa;
else 
    data_out = data_in;



`else   
   


// INPUT VALUES
// zero pad data to 1024b and check to 10b

wire [63:0] ecc_check_64b ;
assign ecc_check_64b = {{(64-ECC_WDTH_CHK){1'b0}},check_in};


assign ecc_data_in = {{(1024-ECC_WDTH_DATA){1'b0}},data_in};
assign ecc_checkword_in = ecc_check_64b[11:0];

//**************** Debug Logic ******************************
reg [1:0] ecc_invert_ff;
reg ecc_wait;
reg [1023:0] ecc_invert;

always_comb 
  begin
     if (PARITY_ECC_N) 
       begin
          ecc_invert = {1024'h0};
          for (int j=0;j<ECC_WDTH_CHK;j=j+1) 
            ecc_invert[j*PAR_RES+:2] = ecc_invert_ff;
       end
     else 
       begin
          ecc_invert = {1022'h0,ecc_invert_ff};
       end
  end // always_comb
   

always_ff @(posedge clk or negedge reset_n)
 begin
  if (~reset_n) begin
    ecc_invert_ff <= 2'h0;
        ecc_wait <= 1'b0;
  end else begin 
   ecc_wait <= (((~ecc_en) & (| ecc_invert_ff)) | ecc_wait) & (~(ecc_wait & (|(~(ecc_invert_2|ecc_invert_1)))));
//   ecc_invert_ff <= 2'h0;//((~ecc_en&(|ecc_invert_ff))|ecc_wait) ? 2'h0 : (ecc_invert_ff|{ecc_invert_2,ecc_invert_1}); //Niantic B0 ECO - izharh - 7_10_08 //!!!yyankile 20/03!!!     
   ecc_invert_ff <= ((~ecc_en&(|ecc_invert_ff))|ecc_wait) ? 2'h0 : (ecc_invert_ff|{ecc_invert_2,ecc_invert_1}); //yyankile 20/03  
  end 
 end


///////////////// ECC GENERATION LOGIC ///////////////////////////  
// This logic is used in both generate mode (to create the checkbits)
// and correct mode (generate checkbits to compare against check_in).
// If the generated checkword matches the input checkword, there is 
// no error.  


/***************************************************** 
 * H Matrix for 1024b generated code (fully populated odd-
 * weight column matrix). Sorted by incrementing column 
 * value. 
 *****************************************************
 * The generation matrix is the H matrix with the order-1 
 * (checkbit) columns deleted.
 *
 * Note that this matrix can be used for ANY word/check
 * width combination up to 1024+12, without wasting check bits:
 *
 * 1-4b data, 4b ECC - only checkwords 0...3 will be nonzero
 * 5-11b data, 5b ECC - only checkwords 0...4 will be nonzero
 * 12-26b data, 6b ECC - only checkwords 0...5 will be nonzero
 * 27-57b data, 7b ECC - only checkwords 0...6 will be nonzero
 * 58-120b data, 8b ECC - only checkwords 0...7 will be nonzero
 * 121-247b data, 9b ECC - only checkwords 0...8 will be nonzero 
 * 248-1024b data, 10b ECC - all checkwords are used
 * 
 *****************************************************/ 





localparam[1023:0] H_MATRIX_VECTOR_1=1024';

localparam[1023:0] H_MATRIX_VECTOR_2=1024';

localparam[1023:0] H_MATRIX_VECTOR_3=1024';

localparam[1023:0] H_MATRIX_VECTOR_4=1024';

localparam[1023:0] H_MATRIX_VECTOR_5=1024';
localparam[1023:0] H_MATRIX_VECTOR_6=1024';
localparam[1023:0] H_MATRIX_VECTOR_7=1024';

localparam[1023:0] H_MATRIX_VECTOR_8=1024';

localparam[1023:0] H_MATRIX_VECTOR_9=1024';

localparam[1023:0] H_MATRIX_VECTOR_10=1024';

localparam[1023:0] H_MATRIX_VECTOR_11=1024';

localparam [1023:0] H_MATRIX_VECTOR_0 =   ~(H_MATRIX_VECTOR_1^
                                               H_MATRIX_VECTOR_2^
                                               H_MATRIX_VECTOR_3^
                                               H_MATRIX_VECTOR_4^
                                               H_MATRIX_VECTOR_5^
                                               H_MATRIX_VECTOR_6^
                                               H_MATRIX_VECTOR_7^
                                               H_MATRIX_VECTOR_8^
                                               H_MATRIX_VECTOR_9^
                                               H_MATRIX_VECTOR_10^
                                               H_MATRIX_VECTOR_11);


// GENERATE CHECKBITS (using the H Matrix)

always_comb 
   begin
      checkword[11] = ^(ecc_data_in & H_MATRIX_VECTOR_11);
      checkword[10] = ^(ecc_data_in & H_MATRIX_VECTOR_10);
      checkword[9] = ^(ecc_data_in & H_MATRIX_VECTOR_9); 
      checkword[8] = ^(ecc_data_in & H_MATRIX_VECTOR_8); 
      checkword[7] = ^(ecc_data_in & H_MATRIX_VECTOR_7); 
      checkword[6] = ^(ecc_data_in & H_MATRIX_VECTOR_6); 
      checkword[5] = ^(ecc_data_in & H_MATRIX_VECTOR_5); 
      checkword[4] = ^(ecc_data_in & H_MATRIX_VECTOR_4); 
      checkword[3] = ^(ecc_data_in & H_MATRIX_VECTOR_3); 
      checkword[2] = ^(ecc_data_in & H_MATRIX_VECTOR_2); 
      checkword[1] = ^(ecc_data_in & H_MATRIX_VECTOR_1); 
      checkword[0] = ^(ecc_data_in & H_MATRIX_VECTOR_0); 
   end 
    



// GENERATE SYNDROME
// The syndrome represents the original checkword xor'ed with the newly 
// calculated checkword.  It is used to generate the correction word 
// within the ECC decoder. 
// Correct_en is used to qualify the syndrome generation, because it
// is not needed in generate mode. This is done for two reasons: power
// savings in the block-- during generate mode the correction XOR
// array is zeroed-- and to allow dataout = datain during generate mode. 

   reg [ECC_WDTH_CHK-1:0] parity_sig;
   reg [ECC_WDTH_CHK-1:0] parity_syndrome;
   

   generate
     if (SAMPLE_SYND == 0) begin: parity_no_sample
       
       always_comb begin                                                          
         parity_sig = {ECC_WDTH_CHK{1'b0}};                     
         if (PARITY_ECC_N) begin                                                     
           for (int i=0;i<ECC_WDTH_CHK;i=i+1) begin                                                
             parity_sig[i] = ^ecc_data_in[i*PAR_RES+:PAR_RES]; 
           end                                                  
         end                                                       
       end // always_comb                                              
       
       always_comb begin                                                          
         parity_syndrome = {ECC_WDTH_CHK{1'b0}};                     
         if (PARITY_ECC_N) begin                                                     
           parity_syndrome = parity_sig ^ check_in;               
         end                                                       
       end                                                            
       
     end else if (PARITY_ECC_N == 0) begin: sample_ecc // block: parity_no_sample

       always_comb begin // these signal are unused in this case ...
         parity_sig      = check_in;                     
         parity_syndrome = check_in;                     
       end

     end
     
   endgenerate

    generate
      if (SAMPLE_SYND && !ECC_SAMPLE_EN_PARAM && PARITY_ECC_N) begin : parity_sample_syndrome

        reg [ECC_WDTH_CHK-1:0] check_in_sampled;

        always_ff @(posedge clk,negedge reset_n) 
          if (!reset_n) begin
            check_in_sampled    <= {ECC_WDTH_CHK{1'b0}};
            parity_sig          <= {ECC_WDTH_CHK{1'b0}};
          end else begin
            check_in_sampled    <= check_in;
            for (int i=0;i<ECC_WDTH_CHK;i=i+1) begin                                               
              parity_sig[i]  <= ^ecc_data_in[i*PAR_RES+:PAR_RES];
            end                                                 
          end

        always_comb begin                                                          
          parity_syndrome = {ECC_WDTH_CHK{1'b0}};                     
          if (PARITY_ECC_N) begin                                                     
            parity_syndrome = parity_sig ^ check_in_sampled;               
          end                                                       
        end
      end // block: parity_sample_syndrome
      
    endgenerate

    generate
      if (SAMPLE_SYND && ECC_SAMPLE_EN_PARAM && PARITY_ECC_N) begin : parity_sample_syndrome_with_sample_en
        
        reg [ECC_WDTH_CHK-1:0] check_in_sampled;
        
        always_ff @(posedge clk,negedge reset_n)
          if (!reset_n) begin
            check_in_sampled <= {ECC_WDTH_CHK{1'b0}};
            parity_sig       <= {ECC_WDTH_CHK{1'b0}};
          end else if (ecc_sample_en) begin
            check_in_sampled    <= check_in;
            for (int i=0;i<ECC_WDTH_CHK;i=i+1) begin                                               
              parity_sig[i]  <= ^ecc_data_in[i*PAR_RES+:PAR_RES];
            end                                                 
          end

        always_comb begin                                                          
          parity_syndrome = {ECC_WDTH_CHK{1'b0}};                     
          if (PARITY_ECC_N) begin                                                     
            parity_syndrome = parity_sig ^ check_in_sampled;               
          end                                                       
        end
      end // block: parity_sample_syndrome_with_sample_en
    endgenerate




/*
   always @* 
     begin
        parity_sig       ={ECC_WDTH_CHK{1'b0}};
        if (PARITY_ECC_N)
          begin
             for (i=0;i<ECC_WDTH_CHK;i=i+1)
               begin
                  parity_sig[i] = ^ecc_data_in[i*PAR_RES+:PAR_RES];
               end          
          end
     end // always_comb

   always @*
     begin
        parity_syndrome  ={ECC_WDTH_CHK{1'b0}};
        if (PARITY_ECC_N)
          begin
             parity_syndrome  =parity_sig ^ check_in;
          end
     end
*/   
// logic new_correct_en;
// `ifdef HLP_FPGA_ALL 
//         assign new_correct_en = 1'b0;
// `else
//         assign new_correct_en = correct_en;
// `endif
   

   generate
      if (SAMPLE_SYND == 0)
        begin : no_sample
           assign corrected_data_1024b = ecc_data_in[1023:0] ^ (new_correct_en ? correction_word[1035:12] : ecc_invert[1023:0]); 
           always_comb  
                syndrome_12b  = new_correct_en ?  (checkword ^ ecc_checkword_in) : 12'h0;
        end
    endgenerate // block: no-sample

    generate   
      if (SAMPLE_SYND && ECC_SAMPLE_EN_PARAM) begin : sample_syndrome_with_sample_en

        reg [ECC_WDTH_DATA-1:0] sampled_data_in;   

        assign corrected_data_1024b = {{(1024-ECC_WDTH_DATA){1'b0}},sampled_data_in} ^ (new_correct_en ? correction_word[1035:12] : ecc_invert[1023:0]); 
        
        always_ff @(posedge clk,negedge reset_n) begin
          if (!reset_n) begin
            sampled_data_in <= {ECC_WDTH_DATA{1'b0}};
            syndrome_12b    <= 12'h0;
          end else if (ecc_sample_en) begin
            syndrome_12b    <= new_correct_en ?  (checkword ^ ecc_checkword_in) : 12'h0;
            sampled_data_in <=data_in;
          end
        end
      end // block: sample_syndrome_with_sample_en
      
    endgenerate

    generate
      if (SAMPLE_SYND && !ECC_SAMPLE_EN_PARAM) begin : sample_syndrome

        reg [ECC_WDTH_DATA-1:0] sampled_data_in;   

        assign corrected_data_1024b = {{(1024-ECC_WDTH_DATA){1'b0}},sampled_data_in} ^ (new_correct_en ? correction_word[1035:12] : ecc_invert[1023:0]); 
        
        always_ff @(posedge clk,negedge reset_n) begin
          if (!reset_n) begin
            sampled_data_in <= {ECC_WDTH_DATA{1'b0}};
            syndrome_12b <= 12'h0;
          end else begin
            syndrome_12b    <= new_correct_en ?  (checkword ^ ecc_checkword_in) : 12'h0;
            sampled_data_in <= data_in;
          end // else: !if(!reset_n)
        end // always @ (posedge clk,negedge reset_n)
      end // block: sample_syndrome
      
   endgenerate
   
           
           
   
wire [63:0] syndrome_64b  ;
assign  syndrome_64b      = {52'h0,syndrome_12b};


assign syndrome = (PARITY_ECC_N)? parity_syndrome : syndrome_64b[ECC_WDTH_CHK-1:0];

// COMPARE CHECK BITS to CHECK INPUT
// This signal is asserted if the original checkword, from memory, and 
// the new checkword, created from data read from memory are different. 
// It indicates that the read data and write data are not identical. 

// assign checkword_mismatch = ( ecc_checkword_in != checkword ); 
// if the syndrome is zero, checkword=ecc_checkword_in and there is no error

assign checkword_mismatch = (PARITY_ECC_N)? |parity_syndrome : |(syndrome_12b);


/////////////////////////////// ECC DECODE LOGIC /////////////////////////////////////// 
// This logic is used in correct mode only. 
//  
// Here, the syndrome is compared with the full 1024 bit matrix to determine which 
// bit is in error. For instance, if the syndrome matches column 8 (syndrome value 
// = 11) then bit 8 is in error and should be flipped. 
// If there are 2 errors, then the syndrome will have an even value. Because the H
// matrix is composed of only odd-weight columns, the syndrome will have no match: 
// This is an uncorrectable error. For greater than 2 errors, the syndrome may
// match a random column in the matrix; the wrong bit may be corrected.  


/***************************************************** 
 * H Matrix for 1024b code (fully populated odd-weight 
 * column matrix). Sorted by incrementing column value. 
 *****************************************************/
localparam[1035:0] D_H_MATRIX_VECTOR_11=1036';
localparam[1035:0] D_H_MATRIX_VECTOR_10=1036';
localparam[1035:0] D_H_MATRIX_VECTOR_9=1036';
localparam[1035:0] D_H_MATRIX_VECTOR_8=1036';
localparam[1035:0] D_H_MATRIX_VECTOR_7=1036';
localparam[1035:0] D_H_MATRIX_VECTOR_6=1036';
localparam[1035:0] D_H_MATRIX_VECTOR_5=1036';
localparam[1035:0] D_H_MATRIX_VECTOR_4=1036';
localparam[1035:0] D_H_MATRIX_VECTOR_3=1036';
localparam[1035:0] D_H_MATRIX_VECTOR_2=1036';
localparam[1035:0] D_H_MATRIX_VECTOR_1=1036';

localparam [1035:0] D_H_MATRIX_VECTOR_0 = ~ (D_H_MATRIX_VECTOR_1^
                                              D_H_MATRIX_VECTOR_2^
                                              D_H_MATRIX_VECTOR_3^
                                              D_H_MATRIX_VECTOR_4^
                                              D_H_MATRIX_VECTOR_5^
                                              D_H_MATRIX_VECTOR_6^
                                              D_H_MATRIX_VECTOR_7^
                                              D_H_MATRIX_VECTOR_8^
                                              D_H_MATRIX_VECTOR_9^
                                              D_H_MATRIX_VECTOR_10^
                                              D_H_MATRIX_VECTOR_11);


// MATCH THE SYNDROME TO COLUMN IN MATRIX - IDENTIFY THE FLIPPED BIT
// A 1024 bit 1-hot vector (correction word) is generated from
// the H matrix, based on where the syndrome matches a column
// value. Where the vector is set a bit has been flipped. 

always_comb 
   begin 
        for ( int N = 0 ; N < 1036 ; N = N + 1) 
           begin 
            if (syndrome_12b == {
                              D_H_MATRIX_VECTOR_11[N],
                              D_H_MATRIX_VECTOR_10[N],
                              D_H_MATRIX_VECTOR_9[N],
                              D_H_MATRIX_VECTOR_8[N],
                              D_H_MATRIX_VECTOR_7[N], 
                              D_H_MATRIX_VECTOR_6[N], 
                              D_H_MATRIX_VECTOR_5[N], 
                              D_H_MATRIX_VECTOR_4[N], 
                              D_H_MATRIX_VECTOR_3[N], 
                              D_H_MATRIX_VECTOR_2[N], 
                              D_H_MATRIX_VECTOR_1[N], 
                              D_H_MATRIX_VECTOR_0[N]} ) 
               correction_word[N] = 1'b1; 
            else 
               correction_word[N] = 1'b0; 
           end   
   end 



// This signal is used to indicate that a correction match has been
// found. If all bits in the correction_word are clear and the two 
// checkwords are different, then an uncorrectable bit error has occurred. 

// assign correction_match = |correction_word; 

// Optional Design Optimization
// alternately: Every entry in the matrix is odd weight; thus 
// the xor of the syndrome bits will be 1. For a fully populated matrix,
// any column outside the matrix has xor = 0. This speeds up the logic

assign correction_match = (PARITY_ECC_N) ? ^parity_syndrome : ^(syndrome_12b);

// For a fully populated matrix (57+7 or 120+8 etc) there is no degradation 
// in coverage- the logic is equivalent. For an underutilized array, all 
// bits are reduced to the SEC-DED coverage of a full matrix---
// Certain random SEC-3ED or 4ED errors caught by a partially populated
// matrix (shorter data word than max word) are not found using this 
// optimization scheme. 


// CORRECT THE OUTPUT DATA
// The correction_word is xor'ed with the original data to flip the errored 
// bit read from memory. 
//
// In generate mode, corrected_data should equal data_in, because the 
// syndrome, and thus correction_word, are zeroed internally


// `ifdef HLP_FPGA_ECC_RDC // tshay, aisraeli, inherit, NNT_???
// // ECC Reduction - In order to remove ECC functionality in FPGA
//   reg [ECC_WDTH_DATA-1:0] data_outa;
//   generate   
//     if (ECC_SAMPLE_EN_PARAM) begin
//       
//       always_ff @(posedge clk or negedge reset_n)        
//         if      (~reset_n     ) data_outa <= {ECC_WDTH_DATA{1'b0}} ;  
//         else if (ecc_sample_en) data_outa <= data_in               ;
// 
//     end else begin
//              
//       always_ff @(posedge clk or negedge reset_n)
//         if (~reset_n) data_outa <= {ECC_WDTH_DATA{1'b0}} ;  
//         else          data_outa <= data_in;                 
//     
//     end
//   endgenerate
// 
// always_comb
// if (SAMPLE_SYND && !PARITY_ECC_N) 
//     data_out = data_outa;
// else 
//     data_out = data_in;
// 
// //assign   data_out = data_in;
// `else 
assign data_out = (PARITY_ECC_N)? {data_in[ECC_WDTH_DATA-1:0]^ecc_invert[ECC_WDTH_DATA-1:0]} : corrected_data_1024b[ECC_WDTH_DATA-1:0];
//assign data_out = (PARITY_ECC_N)? data_in[ECC_WDTH_DATA-1:0] : corrected_data_1024b[ECC_WDTH_DATA-1:0];
//`endif



// OUTPUT CHECK BITS 
// In generation mode, the newly generated checkword is output. 
// In correct mode, the checkword bits are output, properly corrected 
// in a bit was flipped. 

assign corrected_checkword_10b = ecc_checkword_in[11:0] ^ correction_word[11:0];
// `ifdef HLP_FPGA_ECC_RDC // tshay, aisraeli, inherit, NNT_???
// // ECC Reduction - In order to remove ECC functionality in FPGA
// assign check_out = check_in; 
// assign uncorrectable_error = 1'b0;
// assign correctable_error = 1'b0;
// `else   

wire [63:0] corrected_checkword_64b;
wire [63:0] checkword_64b          ;
assign corrected_checkword_64b = {54'h0,corrected_checkword_10b};
assign checkword_64b           = {54'h0,checkword};



assign check_out = (PARITY_ECC_N) ? parity_sig : (new_correct_en) ? corrected_checkword_64b[ECC_WDTH_CHK-1:0] : checkword_64b[ECC_WDTH_CHK-1:0];

// OUTPUT STATUS (correctable error, uncorrectable error)

assign uncorrectable_error = (new_correct_en & checkword_mismatch & (~correction_match|(PARITY_ECC_N)));
assign correctable_error = (PARITY_ECC_N)? 1'b0 : (new_correct_en & checkword_mismatch & correction_match);

`endif

endmodule//mgm_ecc_compute

